class LexUtils{constructor(){this.fps=0,console.log("Lex Utils loaded successfully!")}log(e){if(null==e||""==e||0==e.length)return;let t=new Date;console.log(`[${t.getHours()}:${t.getMinutes()}:${t.getSeconds()}.${t.getMilliseconds()}] ${e}`)}clamp(e,t,l){return e<=t?t:e>=l?l:e}shuffleArray(e){for(let t=e.length-1;t>0;t--){const l=Math.floor(Math.random()*t)[(e[t],e[l])]=[e[l],e[t]]}}between(e,t,l,o){let n=Math.min.apply(Math,[t,l]),r=Math.max.apply(Math,[t,l]);return o?e>=n&&e<=r:e>n&&e<r}showFPS(e,t,l){frameCount%10==0&&(this.fps=frameRate()),push(),fill(51),noStroke(),textSize(20*l),textAlign(CENTER,CENTER),rect(e,t,30*l,30*l),fill(255),text(round(this.fps),(e+15)*l,(t+15)*l),pop()}blockRightClick(e){e.canvas.oncontextmenu=(()=>!1)}sleep(e){return new Promise(t=>setTimeout(t,e))}setScreenRatio(e){if(e>0){let t=windowWidth,l=floor(windowWidth/e);return l>windowHeight&&(l=windowHeight,t=floor(l*e)),{w:t,h:l}}}reverseString(e){return e.split("").reverse().join("")}formatNumber(e){let t=String(e),l="",o=0;for(let e=t.length-1;e>=0;e--)l=t[e]+l,++o%3==0&&0!=e&&(l=","+l);return l}}window.lu=new LexUtils;